import Tesseract from 'tesseract.js';
import { jsPDF } from "jspdf";
import React, { useState, useEffect } from 'react';
import CrmLogoFull from './assets/logo.png';
import { supabase } from './supabaseClient';
import { 
  User, LogOut, Heart, Activity, Zap, Menu, X, 
  UserCircle, Clipboard, Save, Info, ChevronDown, ChevronRight,
  Plus, History, Play, BarChart2, TrendingUp, Download, 
  Lightbulb, Folder, Moon, BookOpen, Bell 
} from 'lucide-react';
import './Dashboard.css';

const HeartAnimation = "https://cdn-icons-png.flaticon.com/512/833/833472.png"; 
const KidneyAnimation = "https://cdn-icons-png.flaticon.com/512/2906/2906231.png";

const Dashboard = ({ user, onLogout }) => {
  // --- 1. STATE MANAGEMENT ---
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [isAnalysing, setIsAnalysing] = useState(false);
  const [showClinicalModal, setShowClinicalModal] = useState(false);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [selectedFiles, setSelectedFiles] = useState([]);
  const [mobileMenu, setMobileMenu] = useState(false);
  const [subMenus, setSubMenus] = useState({ health: false, analysis: false, reports: false });
  const [pastReports, setPastReports] = useState([]);
  const [selectedReport, setSelectedReport] = useState(null);

  const [formData, setFormData] = useState({
    age: '', weight: '', height: '', full_name: '',
    bp_sys: '', bp_dia: '', sugar: '', creatine: '',
    phone: '', address: '', gender: '',
    smoking: 'No', alcohol: 'No', activity: 'Sedentary',
    sleep: '', comorbidities: ''
  });

  // --- 2. DATA ORCHESTRATION ---
  const fetchReports = async () => {
    if (!user) return;
    try {
      const { data, error } = await supabase
        .from('reports')
        .select('*')
        .eq('user_id', user.id)
        .order('created_at', { ascending: false });
      if (error) throw error;
      if (data) setPastReports(data);
    } catch (err) {
      console.error("Vault Error:", err.message);
    }
  };

  const getProfile = async () => {
    if (!user) return;
    try {
      let { data, error } = await supabase.from('profiles').select('*').eq('id', user.id).single();
      if (data) {
        setProfile(data);
        setFormData(prev => ({ ...prev, ...data }));
      }
    } catch (err) {
      console.error("Profile Load Error:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (user) {
      getProfile();
      fetchReports();
    }
  }, [user]);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const toggleSubMenu = (menu) => setSubMenus(prev => ({ ...prev, [menu]: !prev[menu] }));

  // --- 3. AI ANALYSIS & CLINICAL PIPELINE ---
  const runAnalysisAndDownload = async () => {
    setIsAnalysing(true);
    let finalData = { ...formData };
    let ocrLog = "Manual entry verified.";

    try {
      // PHASE A: AI OCR EXTRACTION
      if (selectedFiles.length > 0) {
        const file = selectedFiles[0];
        const { data: { text } } = await Tesseract.recognize(file, 'eng');
        
        const sugarMatch = text.match(/(?:glucose|sugar|glu)\D+(\d{2,3})/i);
        const creatineMatch = text.match(/(?:creatinine|crea)\D+(\d?\.?\d)/i);

        if (sugarMatch) {
          finalData.sugar = sugarMatch[1];
          ocrLog = `AI Extracted Glucose (${sugarMatch[1]}) from ${file.name}`;
        }
        if (creatineMatch) {
          finalData.creatine = creatineMatch[1];
          ocrLog += ` & Creatinine (${creatineMatch[1]}) from report.`;
        }
      }

      // PHASE B: PROFILE SYNC
      const { data: updatedProfile, error: profileErr } = await supabase
        .from('profiles')
        .upsert({ id: user.id, ...finalData })
        .select().single();
      
      if (profileErr) throw profileErr;
      setProfile(updatedProfile);

      // PHASE C: MEDICAL WEIGHTING ENGINE
      const calculateRisk = () => {
        let score = 0;
        if (parseInt(finalData.bp_sys) > 140) score += 35;
        else if (parseInt(finalData.bp_sys) > 130) score += 15;

        if (parseFloat(finalData.creatine) > 1.5) score += 40;
        else if (parseFloat(finalData.creatine) > 1.2) score += 20;

        if (parseInt(finalData.sugar) > 140) score += 25;
        if (parseInt(finalData.age) > 55) score += 10;
        return Math.min(score, 100);
      };
      const riskScore = calculateRisk();

      // PHASE D: DOCUMENT GENERATION (PDF)
      const doc = new jsPDF();
      let y = 20;
      const margin = 20;

      const drawCard = (title, status, color) => {
        doc.setFillColor(248, 250, 252);
        doc.rect(margin, y, 170, 30, 'F');
        doc.setFillColor(color[0], color[1], color[2]);
        doc.rect(margin, y, 2, 30, 'F');
        doc.setTextColor(color[0], color[1], color[2]);
        doc.setFontSize(10); doc.setFont("helvetica", "bold");
        doc.text(title, margin + 5, y + 8);
        doc.setTextColor(30, 41, 59);
        doc.setFontSize(12); doc.text(`STATUS: ${status}`, margin + 5, y + 18);
        y += 35;
      };

      // Header
      doc.setFillColor(15, 23, 42);
      doc.rect(0, 0, 210, 40, 'F');
      doc.setTextColor(255, 255, 255);
      doc.setFontSize(18); doc.text("CRM INTELLIGENT DIAGNOSTIC REPORT", margin, 25);
      
      doc.setFontSize(8);
      const wrappedLog = doc.splitTextToSize(`DATA PROVENANCE: ${ocrLog}`, 170);
      doc.text(wrappedLog, margin, 33);

      y = 60;
      doc.setTextColor(30, 41, 59);
      doc.setFontSize(14); doc.text(`SYSTEMIC RISK SCORE: ${riskScore}%`, margin, y);
      y += 10;

      // Dynamic Analysis Blocks
      const cardiacStatus = formData.bp_sys > 140 ? "Hypertensive Stress" : "Stable";
      const cardiacEasy = formData.bp_sys > 140 ? `High BP (${finalData.bp_sys}). Heart strain detected.` : "Safe BP range.";
      drawCard("CARDIAC ANALYSIS", cardiacStatus, finalData.bp_sys > 140 ? [239, 68, 68] : [16, 185, 129]);
      doc.setFontSize(8); doc.text(`AI Insight: ${cardiacEasy}`, margin + 5, y - 12);

      const renalStatus = finalData.creatine > 1.2 ? "Filtration Stress" : "Optimal";
      const renalEasy = finalData.creatine > 1.2 ? `Creatinine ${finalData.creatine}. Filters struggling.` : "Kidneys filtering well.";
      drawCard("RENAL ANALYSIS", renalStatus, finalData.creatine > 1.2 ? [245, 158, 11] : [16, 185, 129]);
      doc.setFontSize(8); doc.text(`AI Insight: ${renalEasy}`, margin + 5, y - 12);

      const metaStatus = finalData.sugar > 140 ? "Glycemic Imbalance" : "Healthy";
      const metaEasy = finalData.sugar > 140 ? `Sugar ${finalData.sugar}. Imbalance detected.` : "Glucose stable.";
      drawCard("METABOLIC ANALYSIS", metaStatus, finalData.sugar > 140 ? [239, 68, 68] : [16, 185, 129]);
      doc.setFontSize(8); doc.text(`AI Insight: ${metaEasy}`, margin + 5, y - 12);

      doc.save(`CRM_Report_${Date.now()}.pdf`);

      // PHASE E: HEALTH VAULT PERSISTENCE
      const cleanReportData = {
        age: finalData.age, weight: finalData.weight, height: finalData.height,
        bp_sys: finalData.bp_sys, bp_dia: finalData.bp_dia,
        sugar: finalData.sugar, creatine: finalData.creatine,
        smoking: finalData.smoking, activity: finalData.activity
      };

      await supabase.from('reports').insert([{
        user_id: user.id,
        report_name: `Analysis_${new Date().toLocaleDateString()}`,
        report_data: finalData,
        risk_score: riskScore
      }]);

      fetchReports();
      setShowClinicalModal(false);
      setShowProfileModal(false);
      alert("AI Sync Complete. Dashboard and Vault Updated!");

    } catch (err) {
      alert("Analysis Error: " + err.message);
    } finally {
      setIsAnalysing(false);
    }
  };

  if (loading) return <div className="status-screen">Initializing CRM Engine...</div>;

  const bmi = profile?.height ? (profile.weight / (profile.height / 100) ** 2).toFixed(1) : '--';

  return (
    <div className="dashboard-container">
      {/* HEADER SECTION */}
      <header className="dash-header">
        <div className="dash-nav-logo">
          <span className="logo-text">CRM Analysis</span>
          <img src={CrmLogoFull} alt="Logo" className="header-logo" />
        </div>
        <div className="nav-controls">
          <span className="user-welcome desktop-only-controls">
            Welcome, {profile?.full_name?.split(' ')[0] || 'User'}
          </span>
          <button className="mobile-menu-btn" onClick={() => setMobileMenu(!mobileMenu)}>
            {mobileMenu ? <X /> : <Menu />}
          </button>
        </div>
      </header>

      <div className="dash-main-wrapper">
        {/* SIDEBAR NAVIGATION */}
        <aside className={`dash-sidebar ${mobileMenu ? 'active' : ''}`}>
          <div className="sidebar-header">
            <UserCircle size={50} color="#6366f1" />
            <h2 className="user-name">{profile?.full_name || "Patient"}</h2>
          </div>
          <nav className="sidebar-nav">
            <a className="nav-item active"><Activity size={18} /> <span>Dashboard</span></a>
            
            <div className={`nav-group ${subMenus.health ? 'open' : ''}`}>
              <button className="nav-item-btn" onClick={() => toggleSubMenu('health')}>
                <Heart size={18} /> <span>Health</span>
                <span className="chevron-icon">{subMenus.health ? <ChevronDown size={14} /> : <ChevronRight size={14} />}</span>
              </button>
              <div className="sub-menu">
                <button className="sub-link-btn" onClick={() => setShowClinicalModal(true)}>
                  <Plus size={14} /> <span>Clinical Center</span>
                </button>
                <a href="#records" className="sub-link"><History size={14} /> Records</a>
              </div>
            </div>

            <button className="nav-item-btn" onClick={() => toggleSubMenu('reports')}>
              <Folder size={18} /> <span>My Health Vault</span>
            </button>
            {subMenus.reports && (
              <div className="sub-menu" style={{display:'flex', flexDirection:'column'}}>
                {pastReports.length > 0 ? pastReports.map(report => (
                  <button key={report.id} className="sub-link-btn" onClick={() => setSelectedReport(report)}>
                    <BookOpen size={12} /> {new Date(report.created_at).toLocaleDateString()}
                  </button>
                )) : <small style={{padding:'10px', color:'#94a3b8'}}>No reports saved</small>}
              </div>
            )}

            <button className="nav-item-btn" onClick={() => setShowProfileModal(true)}>
              <Clipboard size={18} /> <span>Update Profile</span>
            </button>
            <button onClick={onLogout} className="sidebar-logout-btn"><LogOut size={16} /> <span>Logout</span></button>
          </nav>
        </aside>

        {/* CENTER CONTENT AREA */}
        <main className="dash-content-area">
          <div className="content-header"><h1>Clinical Overview</h1></div>

          {/* PATIENT SUMMARY CARD */}
          {profile && (
            <section className="user-profile-summary-card">
              <div className="profile-card-content">
                <div className="profile-main-info">
                  <h3>{profile.full_name || 'Patient Name'}</h3>
                  <p>ID: {user?.id.slice(0, 8)} | {profile.age || '--'} Yrs | {profile.gender || 'Not Set'}</p>
                </div>
                <div className="profile-tags">
                  <span className="p-tag">BP: {profile.bp_sys || '--'}/{profile.bp_dia || '--'}</span>
                  <span className="p-tag">Sugar: {profile.sugar || '--'} mg/dL</span>
                  <span className={`p-tag ${profile.smoking === 'Yes' ? 'warning' : 'lifestyle'}`}>
                    Smoking: {profile.smoking || 'No'}
                  </span>
                  <span className="p-tag lifestyle">Activity: {profile.activity || 'Not Set'}</span>
                  <span className="p-tag">Sleep: {profile.sleep ? `${profile.sleep}h` : 'Not Set'}</span>
                </div>
              </div>
            </section>
          )}

          {/* INTERNAL REPORT VIEWER */}
          {selectedReport && (
            <div className="report-viewer-overlay glass-overlay">
              <div className="report-viewer-card glass-modal">
                <div className="modal-header-fixed">
                  <h3>Archive: {selectedReport.report_name}</h3>
                  <button onClick={() => setSelectedReport(null)}><X /></button>
                </div>
                <div className="report-view-body">
                  <div className="risk-banner" style={{background: selectedReport.risk_score > 60 ? '#ef4444' : '#10b981'}}>
                    AI RISK SCORE: {selectedReport.risk_score}%
                  </div>
                  <div className="report-stats-grid">
                    <div className="stat-pill">BP: {selectedReport.report_data.bp_sys}/{selectedReport.report_data.bp_dia}</div>
                    <div className="stat-pill">Glucose: {selectedReport.report_data.sugar} mg/dL</div>
                    <div className="stat-pill">Creatine: {selectedReport.report_data.creatine} mg/dL</div>
                  </div>
                  <p className="report-narrative">
                    This analysis was performed on {new Date(selectedReport.created_at).toLocaleString()}. 
                    The AI detected {selectedReport.risk_score > 60 ? 'significant' : 'minimal'} systemic stress based on archived data.
                  </p>
                </div>
              </div>
            </div>
          )}

          {/* VITALS GRID */}
          <section className="crm-grid">
            <div className={`crm-status-box ${profile?.bp_sys > 140 ? 'status-critical' : ''}`}>
              <img src={HeartAnimation} className="crm-animated-icon" alt="heart" />
              <div className="crm-info">
                <h4>Cardiac</h4>
                <div className="crm-reading">{profile?.bp_sys || '--'}/{profile?.bp_dia || '--'} <small>mmHg</small></div>
              </div>
            </div>
            <div className={`crm-status-box ${profile?.creatine > 1.2 ? 'status-critical' : ''}`}>
              <img src={KidneyAnimation} className="crm-animated-icon" alt="kidney" />
              <div className="crm-info">
                <h4>Renal</h4>
                <div className="crm-reading">{profile?.creatine || '--'} <small>mg/dL</small></div>
              </div>
            </div>
            <div className={`crm-status-box ${profile?.sugar > 140 ? 'status-critical' : ''}`}>
              <div className="crm-icon-wrapper"><Zap size={30} color="#f59e0b" /></div>
              <div className="crm-info">
                <h4>Metabolic</h4>
                <div className="crm-reading">{profile?.sugar || '--'} <small>mg/dL</small></div>
              </div>
            </div>
          </section>

          {/* LIFESTYLE & BMI CARDS */}
          <div className="lifestyle-row">
            <section className="lifestyle-card">
              <span className="card-main-title">Clinical Summary</span>
              <div className="main-metric-display">{profile?.age || '--'} <span className="metric-unit">Yrs</span></div>
              <p>Status: <strong>{profile?.bp_sys > 140 ? 'High Risk' : 'Stable'}</strong></p>
            </section>
            <section className="lifestyle-card">
              <span className="card-main-title">Body Composition</span>
              <div className="main-metric-display">{bmi} <span className="metric-unit">BMI</span></div>
              <p>{bmi > 25 ? 'Overweight Range' : 'Normal Range'}</p>
            </section>
          </div>
        </main>

        {/* RIGHT PANEL - QUICK ACTIONS */}
        <aside className="dash-right-panel">
          <div className="summary-card">
            <h3><Info size={18} /> Quick Actions</h3>
            <button className="btn-primary-save" style={{width:'100%', marginTop:'10px'}} onClick={() => setShowClinicalModal(true)}>New Analysis</button>
            <div className="mini-alert" style={{marginTop:'20px'}}>
              <p><Zap size={14} /> AI Recommendation:</p>
              <small>{profile?.bp_sys > 140 ? "Restrict Sodium immediately." : "Vitals appear normal."}</small>
            </div>
          </div>
        </aside>
      </div>

      {/* --- UPDATED CLINICAL CENTER MODAL: UNIFIED DATA ENTRY --- */}
{showClinicalModal && (
  <div className="modal-overlay">
    <div className="profile-modal-container unified-clinical-modal">
      <div className="modal-header-fixed">
        <h2>Clinical Intelligence Center</h2>
        <button onClick={() => setShowClinicalModal(false)}><X /></button>
      </div>
      
      <div className="modal-body-scroll">
        <div className="unified-grid profile-expanded-grid" style={{gridTemplateColumns: 'repeat(3, 1fr)', gap: '20px', padding: '20px'}}>
          
          {/* Section 1: Vital Biomarkers */}
          <div className="clinical-form-side">
            <h4 className="sub-section-title"><Activity size={14} /> Vital Biomarkers</h4>
            <div className="input-compact-grid">
              <div className="field-group">
                <label>Systolic BP</label>
                <input type="number" name="bp_sys" value={formData.bp_sys} onChange={handleInputChange} placeholder="120"/>
              </div>
              <div className="field-group">
                <label>Diastolic BP</label>
                <input type="number" name="bp_dia" value={formData.bp_dia} onChange={handleInputChange} placeholder="80"/>
              </div>
            </div>
            <div className="field-group" style={{marginTop: '10px'}}>
              <label>Blood Sugar (mg/dL)</label>
              <input type="number" name="sugar" value={formData.sugar} onChange={handleInputChange} placeholder="100"/>
            </div>
            <div className="field-group" style={{marginTop: '10px'}}>
              <label>Creatine (mg/dL)</label>
              <input type="number" step="0.1" name="creatine" value={formData.creatine} onChange={handleInputChange} placeholder="1.0"/>
            </div>
          </div>

          {/* Section 2: Lifestyle Factors (From Dashboard Top Card) */}
          <div className="clinical-form-side">
            <h4 className="sub-section-title"><Zap size={14} /> Lifestyle Factors</h4>
            <div className="field-group">
              <label>Smoking Status</label>
              <select name="smoking" value={formData.smoking} onChange={handleInputChange}>
                <option value="No">No (Non-Smoker)</option>
                <option value="Yes">Yes (Current Smoker)</option>
              </select>
            </div>
            <div className="field-group" style={{marginTop: '10px'}}>
              <label>Physical Activity</label>
              <select name="activity" value={formData.activity} onChange={handleInputChange}>
                <option value="Sedentary">Sedentary</option>
                <option value="Moderate">Moderate</option>
                <option value="Active">Active</option>
              </select>
            </div>
            <div className="field-group" style={{marginTop: '10px'}}>
              <label>Sleep Schedule (Avg Hrs)</label>
              <input type="number" name="sleep" value={formData.sleep} onChange={handleInputChange} placeholder="e.g. 8"/>
            </div>
          </div>

          {/* Section 3: Document Upload & History */}
          <div className="clinical-form-side">
            <h4 className="sub-section-title"><Folder size={14} /> AI Document Scan</h4>
            <div className="compact-upload-zone">
              <input type="file" multiple onChange={(e) => setSelectedFiles(Array.from(e.target.files))} id="f-up-clinical" style={{display:'none'}}/>
              <label htmlFor="f-up-clinical">
                <Folder size={40} color="#6366f1" />
                <p style={{fontSize: '0.8rem', fontWeight: '600'}}>Click to Upload Lab Report</p>
                <span style={{fontSize: '0.7rem', color: '#64748b'}}>{selectedFiles.length} files selected</span>
              </label>
            </div>
            <div className="field-group" style={{marginTop: '15px'}}>
              <label>Medical Notes</label>
              <textarea name="comorbidities" value={formData.comorbidities} onChange={handleInputChange} rows="2" placeholder="Any new symptoms?" style={{fontSize: '0.8rem'}}/>
            </div>
          </div>

        </div>
      </div>

      <div className="modal-footer-fixed">
        <button className="btn-primary-save" onClick={runAnalysisAndDownload} disabled={isAnalysing}>
          {isAnalysing ? "AI Syncing All Vitals..." : "Run Unified Analysis & Update Dashboard"}
        </button>
      </div>
    </div>
  </div>
)}

      {/* --- MODAL 2: UPDATE PROFILE (Deep Medical History) --- */}
      {showProfileModal && (
        <div className="modal-overlay glass-overlay">
          <div className="profile-modal-container glass-modal">
            <div className="modal-header-fixed">
              <h2>Patient Medical Record</h2>
              <button onClick={() => setShowProfileModal(false)}><X /></button>
            </div>
            <div className="modal-body-scroll">
              <div className="unified-grid profile-expanded-grid">
                {/* Column 1: Identity */}
                <div className="clinical-form-side">
                  <h4 className="sub-section-title"><User size={14} /> Identity & Contact</h4>
                  <div className="field-group"><label>Full Name</label><input type="text" name="full_name" value={formData.full_name} onChange={handleInputChange} /></div>
                  <div className="field-group"><label>Phone Number</label><input type="text" name="phone" value={formData.phone} onChange={handleInputChange} /></div>
                  <div className="field-group"><label>Address</label><input type="text" name="address" value={formData.address} onChange={handleInputChange} /></div>
                  <div className="field-group">
                    <label>Gender</label>
                    <select name="gender" value={formData.gender} onChange={handleInputChange}>
                      <option value="">Select</option>
                      <option value="Male">Male</option>
                      <option value="Female">Female</option>
                    </select>
                  </div>
                </div>

                {/* Column 2: Lifestyle */}
                <div className="clinical-form-side">
                  <h4 className="sub-section-title"><Zap size={14} /> Lifestyle Profile</h4>
                  <div className="input-compact-grid">
                    <div className="field-group">
                      <label>Smoking</label>
                      <select name="smoking" value={formData.smoking} onChange={handleInputChange}>
                        <option value="No">No</option><option value="Yes">Yes</option>
                      </select>
                    </div>
                    <div className="field-group">
                      <label>Alcohol</label>
                      <select name="alcohol" value={formData.alcohol} onChange={handleInputChange}>
                        <option value="No">No</option><option value="Yes">Yes</option>
                      </select>
                    </div>
                  </div>
                  <div className="field-group">
                    <label>Physical Activity</label>
                    <select name="activity" value={formData.activity} onChange={handleInputChange}>
                      <option value="Sedentary">Sedentary</option>
                      <option value="Moderate">Moderate</option>
                      <option value="Active">Active</option>
                    </select>
                  </div>
                  <div className="field-group"><label>Sleep (Avg Hrs)</label><input type="number" name="sleep" value={formData.sleep} onChange={handleInputChange} /></div>
                </div>

                {/* Column 3: Medical History */}
                <div className="clinical-form-side">
                  <h4 className="sub-section-title"><Activity size={14} /> Clinical History</h4>
                  <div className="field-group">
                    <label>Existing Health Problems</label>
                    <textarea name="comorbidities" value={formData.comorbidities} onChange={handleInputChange} placeholder="Describe conditions..." rows="4" />
                  </div>
                  <div className="input-compact-grid">
                    <div className="field-group"><label>Weight (kg)</label><input type="number" name="weight" value={formData.weight} onChange={handleInputChange} /></div>
                    <div className="field-group"><label>Height (cm)</label><input type="number" name="height" value={formData.height} onChange={handleInputChange} /></div>
                  </div>
                </div>
              </div>
            </div>
            <div className="modal-footer-fixed">
              <button className="btn-primary-save" onClick={runAnalysisAndDownload}>Save Medical Profile</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;
